// src/modules/projects/routes.js
const express = require('express');
const router = express.Router();
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    if (error.code === 'DUPLICATE') {
      return sendError(res, 409, 'DUPLICATE', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/:projectId', async (req, res) => {
  const { projectId } = req.params;
  try {
    const project = await projectsService.getProjectById(projectId);
    if (!project) {
      return sendError(res, 404, 'NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
const projectsStore = [];

const createProject = (name) => {
  const existingProject = projectsStore.find(project => project.name === name);
  if (existingProject) {
    throw { code: 'DUPLICATE', message: 'Project already exists' };
  }
  const project = {
    id: randomUUID(),
    name,
  };
  projectsStore.push(project);
  return project;
};

const getProjects = () => {
  return projectsStore;
};

const getProjectById = (projectId) => {
  return projectsStore.find(project => project.id === projectId);
};

module.exports = {
  createProject,
  getProjects,
  getProjectById,
};

// src/modules/tasks/routes.js
const express = require('express');
const router = express.Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const task = await tasksService.createTask(name);
    res.status(201).json({ task });
  } catch (error) {
    if (error.code === 'DUPLICATE') {
      return sendError(res, 409, 'DUPLICATE', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getTasks(status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || ![ 'todo', 'done' ].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const updatedTask = await tasksService.updateTask(taskId, status);
    res.json({ task: updatedTask });
  } catch (error) {
    if (error.code === 'NOT_FOUND') {
      return sendError(res, 404, 'NOT_FOUND', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const tasksStore = [];

const createTask = (name) => {
  const task = {
    id: randomUUID(),
    name,
    status: 'todo',
  };
  tasksStore.push(task);
  return task;
};

const getTasks = (status) => {
  if (!status) {
    return tasksStore;
  }
  return tasksStore.filter(task => task.status === status);
};

const updateTask = async (taskId, newStatus) => {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    throw { code: 'NOT_FOUND', message: 'Task not found' };
  }
  tasksStore[taskIndex].status = newStatus;
  return tasksStore[taskIndex];
};

const getTaskById = (taskId) => {
  return tasksStore.find(task => task.id === taskId);
};

module.exports = {
  createTask,
  getTasks,
  updateTask,
  getTaskById,
};

// src/modules/members/routes.js
const express = require('express');
const router = express.Router();
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const member = await membersService.createMember(userId, role);
    res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'DUPLICATE') {
      return sendError(res, 409, 'DUPLICATE', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const membersStore = [];

const createMember = (userId, role) => {
  const existingMember = membersStore.find(member => member.userId === userId);
  if (existingMember) {
    throw { code: 'DUPLICATE', message: 'Member already exists' };
  }
  const member = {
    id: randomUUID(),
    userId,
    role,
  };
  membersStore.push(member);
  return member;
};

module.exports = {
  createMember,
};

// src/modules/comments/routes.js
const express = require('express');
const router = express.Router();
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const comment = await commentsService.createComment(taskId, message);
    res.status(201).json({ comment });
  } catch (error) {
    if (error.code === 'NOT_FOUND') {
      return sendError(res, 404, 'NOT_FOUND', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');

const commentsStore = [];

const createComment = async (taskId, message) => {
  const task = await tasksService.getTaskById(taskId);
  if (!task) {
    throw { code: 'NOT_FOUND', message: 'Task not found' };
  }
  const comment = {
    id: randomUUID(),
    taskId,
    message,
  };
  commentsStore.push(comment);
  return comment;
};

module.exports = {
  createComment,
};

// src/lib/errors.js
const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = {
  sendError,
};

const { randomUUID } = require('crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };
